#include <string.h>
#include <stdio.h>
#include <stdlib.h>
#include "mmt_lib.h"

static char* python_script_path = "/opt/mmt/security/python_scripts_and_models/uc4_cicflow_dos.py";
//static char* python_script_path = "/home/pqv/Documents/ocpp/uc4_cicflow_dos.py";

#include <stdbool.h>

static bool em_predict_attack

(const char* Flow_ID, const char* Src_IP, int Src_Port, const char* Dst_IP, 
int Dst_Port, int Protocol, const char* Timestamp, float Flow_Duration, 
int Total_Fwd_Packet, int Total_Bwd_packets, float Total_Length_of_Fwd_Packet, 
float Total_Length_of_Bwd_Packet, float Fwd_Packet_Length_Max, float Fwd_Packet_Length_Min, 
float Fwd_Packet_Length_Mean, float Fwd_Packet_Length_Std, float Bwd_Packet_Length_Max, 
float Bwd_Packet_Length_Min, float Bwd_Packet_Length_Mean, float Bwd_Packet_Length_Std, 
float Flow_Bytes_per_s, float Flow_Packets_per_s, float Flow_IAT_Mean, float Flow_IAT_Std, 
float Flow_IAT_Max, float Flow_IAT_Min, float Fwd_IAT_Total, float Fwd_IAT_Mean, 
float Fwd_IAT_Std, float Fwd_IAT_Max, float Fwd_IAT_Min, float Bwd_IAT_Total, 
float Bwd_IAT_Mean, float Bwd_IAT_Std, float Bwd_IAT_Max, float Bwd_IAT_Min, 
int Fwd_PSH_Flags, int Bwd_PSH_Flags, int Fwd_URG_Flags, int Bwd_URG_Flags, 
int Fwd_Header_Length, int Bwd_Header_Length, float Fwd_Packets_per_s, 
float Bwd_Packets_per_s, float Packet_Length_Min, float Packet_Length_Max, 
float Packet_Length_Mean, float Packet_Length_Std, float Packet_Length_Variance, 
int FIN_Flag_Count, int SYN_Flag_Count, int RST_Flag_Count, int PSH_Flag_Count, 
int ACK_Flag_Count, int URG_Flag_Count, int CWR_Flag_Count, int ECE_Flag_Count, 
float Down_per_Up_Ratio, float Average_Packet_Size, float Fwd_Segment_Size_Avg, 
float Bwd_Segment_Size_Avg, int Bwd_Bytes_per_Bulk_Avg, int Fwd_Bytes_per_Bulk_Avg, 
int Bwd_Bulk_Rate_Avg, int Fwd_Packet_per_Bulk_Avg, int Bwd_Packet_per_Bulk_Avg, 
int Fwd_Bulk_Rate_Avg, int Subflow_Fwd_Packets, int Subflow_Fwd_Bytes, 
int Subflow_Bwd_Packets, int Subflow_Bwd_Bytes, int FWD_Init_Win_Bytes, 
int Bwd_Init_Win_Bytes, int Fwd_Act_Data_Pkts, int Fwd_Seg_Size_Min, 
float Active_Mean, float Active_Std, float Active_Max, float Active_Min, 
float Idle_Mean, float Idle_Std, float Idle_Max, float Idle_Min, const char* Label, 
const char* id) 

{
    char buffer[4096];
    char command[8192];

    snprintf(buffer, sizeof(buffer),
            "Flow_ID=%s,Src_IP=%s,Src_Port=%d,Dst_IP=%s,Dst_Port=%d,Protocol=%d,"
            "Timestamp=%s,Flow_Duration=%f,Total_Fwd_Packet=%d,Total_Bwd_packets=%d,"
            "Total_Length_of_Fwd_Packet=%f,Total_Length_of_Bwd_Packet=%f,Fwd_Packet_Length_Max=%f,"
            "Fwd_Packet_Length_Min=%f,Fwd_Packet_Length_Mean=%f,Fwd_Packet_Length_Std=%f,"
            "Bwd_Packet_Length_Max=%f,Bwd_Packet_Length_Min=%f,Bwd_Packet_Length_Mean=%f,"
            "Bwd_Packet_Length_Std=%f,Flow_Bytes_per_s=%f,Flow_Packets_per_s=%f,"
            "Flow_IAT_Mean=%f,Flow_IAT_Std=%f,Flow_IAT_Max=%f,Flow_IAT_Min=%f,"
            "Fwd_IAT_Total=%f,Fwd_IAT_Mean=%f,Fwd_IAT_Std=%f,Fwd_IAT_Max=%f,"
            "Fwd_IAT_Min=%f,Bwd_IAT_Total=%f,Bwd_IAT_Mean=%f,Bwd_IAT_Std=%f,"
            "Bwd_IAT_Max=%f,Bwd_IAT_Min=%f,Fwd_PSH_Flags=%d,Bwd_PSH_Flags=%d,"
            "Fwd_URG_Flags=%d,Bwd_URG_Flags=%d,Fwd_Header_Length=%d,Bwd_Header_Length=%d,"
            "Fwd_Packets_per_s=%f,Bwd_Packets_per_s=%f,Packet_Length_Min=%f,Packet_Length_Max=%f,"
            "Packet_Length_Mean=%f,Packet_Length_Std=%f,Packet_Length_Variance=%f,"
            "FIN_Flag_Count=%d,SYN_Flag_Count=%d,RST_Flag_Count=%d,PSH_Flag_Count=%d,ACK_Flag_Count=%d,"
            "URG_Flag_Count=%d,CWR_Flag_Count=%d,ECE_Flag_Count=%d,Down_per_Up_Ratio=%f,"
            "Average_Packet_Size=%f,Fwd_Segment_Size_Avg=%f,Bwd_Segment_Size_Avg=%f,"
            "Bwd_Bytes_per_Bulk_Avg=%d,Fwd_Bytes_per_Bulk_Avg=%d,Bwd_Bulk_Rate_Avg=%d,"
            "Fwd_Packet_per_Bulk_Avg=%d,Bwd_Packet_per_Bulk_Avg=%d,Fwd_Bulk_Rate_Avg=%d,"
            "Subflow_Fwd_Packets=%d,Subflow_Fwd_Bytes=%d,Subflow_Bwd_Packets=%d,Subflow_Bwd_Bytes=%d,"
            "FWD_Init_Win_Bytes=%d,Bwd_Init_Win_Bytes=%d,Fwd_Act_Data_Pkts=%d,Fwd_Seg_Size_Min=%d,"
            "Active_Mean=%f,Active_Std=%f,Active_Max=%f,Active_Min=%f,"
            "Idle_Mean=%f,Idle_Std=%f,Idle_Max=%f,Idle_Min=%f,Label=%s,id=%s",
            Flow_ID, Src_IP, Src_Port, Dst_IP, Dst_Port, Protocol, Timestamp, 
            Flow_Duration, Total_Fwd_Packet, Total_Bwd_packets, 
            Total_Length_of_Fwd_Packet, Total_Length_of_Bwd_Packet, 
            Fwd_Packet_Length_Max, Fwd_Packet_Length_Min, Fwd_Packet_Length_Mean, 
            Fwd_Packet_Length_Std, Bwd_Packet_Length_Max, Bwd_Packet_Length_Min, 
            Bwd_Packet_Length_Mean, Bwd_Packet_Length_Std, Flow_Bytes_per_s, 
            Flow_Packets_per_s, Flow_IAT_Mean, Flow_IAT_Std, Flow_IAT_Max, 
            Flow_IAT_Min, Fwd_IAT_Total, Fwd_IAT_Mean, Fwd_IAT_Std, Fwd_IAT_Max, 
            Fwd_IAT_Min, Bwd_IAT_Total, Bwd_IAT_Mean, Bwd_IAT_Std, Bwd_IAT_Max, 
            Bwd_IAT_Min, Fwd_PSH_Flags, Bwd_PSH_Flags, Fwd_URG_Flags, 
            Bwd_URG_Flags, Fwd_Header_Length, Bwd_Header_Length, 
            Fwd_Packets_per_s, Bwd_Packets_per_s, Packet_Length_Min, 
            Packet_Length_Max, Packet_Length_Mean, Packet_Length_Std, 
            Packet_Length_Variance, FIN_Flag_Count, SYN_Flag_Count, 
            RST_Flag_Count, PSH_Flag_Count, ACK_Flag_Count, URG_Flag_Count, 
            CWR_Flag_Count, ECE_Flag_Count, Down_per_Up_Ratio, Average_Packet_Size, 
            Fwd_Segment_Size_Avg, Bwd_Segment_Size_Avg, Bwd_Bytes_per_Bulk_Avg,
            Fwd_Bytes_per_Bulk_Avg, Bwd_Bulk_Rate_Avg, Fwd_Packet_per_Bulk_Avg,
            Bwd_Packet_per_Bulk_Avg, Fwd_Bulk_Rate_Avg, Subflow_Fwd_Packets, 
            Subflow_Fwd_Bytes, Subflow_Bwd_Packets, Subflow_Bwd_Bytes, 
            FWD_Init_Win_Bytes, Bwd_Init_Win_Bytes, Fwd_Act_Data_Pkts, 
            Fwd_Seg_Size_Min, Active_Mean, Active_Std, Active_Max, Active_Min, 
            Idle_Mean, Idle_Std, Idle_Max, Idle_Min, Label, id);


    char result[128];
    char last_result[128] = "";
    int prediction;

    // Command to call the Python script
    //snprintf(command, sizeof(command),
    //         "bash -c 'cd /home/pqv/Documents/ocpp/ && source .venv/bin/activate && python3 %s \"%s\"'",
    //         python_script_path, buffer);

    snprintf(command, sizeof(command),
             "bash -c 'python3 %s \"%s\"'",
             python_script_path, buffer);


    FILE *fp = popen(command, "r");
    if (fp == NULL) {
        fprintf(stderr, "Failed to run Python script.\n");
        return -5;
    }

    // Read the output line by line
    while (fgets(result, sizeof(result), fp) != NULL) {
        // Store the current line into `last_result`
        strncpy(last_result, result, sizeof(last_result) - 1);
        last_result[sizeof(last_result) - 1] = '\0';  // Ensure null-termination
    }

    // Close the pipe
    pclose(fp);

    // Check if we captured any output
    if (strlen(last_result) == 0) {
        fprintf(stderr, "No output from Python script.\n");
        return -1;
    }

    // Trim any trailing newline or whitespace from `last_result`
    size_t len = strlen(last_result);
    if (len > 0 && last_result[len - 1] == '\n') {
        last_result[len - 1] = '\0';
    }

    prediction = atoi(last_result);
    //printf("Prediction is %d\n", prediction);
    //printf("last_result is %s\n", last_result);
    return prediction;
}
